// Validate secret and extract action + data
const data = $input.first().json;
const body = data.body || data;

const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');

const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

const action = body.action || 'sync_content';
const payload = body.data || body;

// Valid actions
const VALID_ACTIONS = ['create_work_item', 'create_cycle', 'add_to_cycle', 'sync_content'];
if (!VALID_ACTIONS.includes(action)) {
  throw new Error(`Unknown action: ${action}. Valid: ${VALID_ACTIONS.join(', ')}`);
}

return [{ json: { action, data: payload } }];

// Create a Plane work item for a content entry
const { action, data } = $input.first().json;

const slug      = $env.PLANE_WORKSPACE_SLUG;
const projectId = $env.PLANE_CF_PROJECT_ID;
const moduleId  = $env.PLANE_CF_MODULE_ID;
const apiKey    = $env.PLANE_API_KEY;
const baseUrl   = $env.PLANE_PUBLIC_URL;

if (!apiKey)    throw new Error('PLANE_API_KEY not configured');
if (!slug)      throw new Error('PLANE_WORKSPACE_SLUG not configured');
if (!projectId) throw new Error('PLANE_CF_PROJECT_ID not configured');

const workItem = await $http.request({
  method: 'POST',
  url: `${baseUrl}/api/v1/workspaces/${slug}/projects/${projectId}/work-items/`,
  headers: {
    'X-API-Key': apiKey,
    'Content-Type': 'application/json'
  },
  body: {
    name: data.title || data.name || `Content ${data.content_id}`,
    description_html: `<p>Format: ${data.format || 'reel'}</p><p>Brief: ${data.brief_summary || data.brief || ''}</p>`,
    start_date: data.created_date || null,
    target_date: data.publish_date || null,
    module: moduleId || undefined
  }
});

return [{ json: { action, plane_response: workItem, work_item_id: workItem.id } }];

// Create a Plane cycle representing a content drop
const { action, data } = $input.first().json;

const slug      = $env.PLANE_WORKSPACE_SLUG;
const projectId = $env.PLANE_CF_PROJECT_ID;
const apiKey    = $env.PLANE_API_KEY;
const baseUrl   = $env.PLANE_PUBLIC_URL;

if (!apiKey)    throw new Error('PLANE_API_KEY not configured');
if (!slug)      throw new Error('PLANE_WORKSPACE_SLUG not configured');
if (!projectId) throw new Error('PLANE_CF_PROJECT_ID not configured');

if (!data.cycle_name) throw new Error('Missing required field: data.cycle_name');

const cycle = await $http.request({
  method: 'POST',
  url: `${baseUrl}/api/v1/workspaces/${slug}/projects/${projectId}/cycles/`,
  headers: {
    'X-API-Key': apiKey,
    'Content-Type': 'application/json'
  },
  body: {
    name: data.cycle_name,
    start_date: data.start_date || null,
    end_date:   data.end_date   || null
  }
});

return [{ json: { action, plane_response: cycle, cycle_id: cycle.id } }];

// Add work items to a Plane cycle
const { action, data } = $input.first().json;

const slug      = $env.PLANE_WORKSPACE_SLUG;
const projectId = $env.PLANE_CF_PROJECT_ID;
const apiKey    = $env.PLANE_API_KEY;
const baseUrl   = $env.PLANE_PUBLIC_URL;

if (!apiKey)          throw new Error('PLANE_API_KEY not configured');
if (!slug)            throw new Error('PLANE_WORKSPACE_SLUG not configured');
if (!projectId)       throw new Error('PLANE_CF_PROJECT_ID not configured');
if (!data.cycle_id)   throw new Error('Missing required field: data.cycle_id');
if (!data.work_item_ids || !data.work_item_ids.length) throw new Error('Missing required field: data.work_item_ids');

const result = await $http.request({
  method: 'POST',
  url: `${baseUrl}/api/v1/workspaces/${slug}/projects/${projectId}/cycles/${data.cycle_id}/cycle-issues/`,
  headers: {
    'X-API-Key': apiKey,
    'Content-Type': 'application/json'
  },
  body: {
    issues: data.work_item_ids
  }
});

return [{ json: { action, plane_response: result, cycle_id: data.cycle_id, added_count: data.work_item_ids.length } }];

// Sync content: check if work item exists in Plane, create or update
// Triggered by NocoDB webhook on content row creation
const { action, data } = $input.first().json;

const slug      = $env.PLANE_WORKSPACE_SLUG;
const projectId = $env.PLANE_CF_PROJECT_ID;
const moduleId  = $env.PLANE_CF_MODULE_ID;
const apiKey    = $env.PLANE_API_KEY;
const baseUrl   = $env.PLANE_PUBLIC_URL;

if (!apiKey)    throw new Error('PLANE_API_KEY not configured');
if (!slug)      throw new Error('PLANE_WORKSPACE_SLUG not configured');
if (!projectId) throw new Error('PLANE_CF_PROJECT_ID not configured');

// Read content from NocoDB via cf-read-content if content_id provided
let contentData = { ...data };
if (data.content_id) {
  try {
    const contentResp = await $http.request({
      method: 'POST',
      url: 'http://localhost:5678/webhook/cf-read-content',
      headers: { 'Content-Type': 'application/json' },
      body: {
        secret: $env.N8N_WEBHOOK_HMAC_SECRET,
        action: 'read_content',
        content_id: data.content_id
      }
    });
    const content = contentResp.body || contentResp;
    contentData = { ...contentData, ...content };
  } catch (e) {
    console.error('cf-read-content failed:', e.message);
  }
}

const itemName = contentData.title || contentData.name || `Content ${data.content_id}`;

// Search for existing work item by name
let existingId = null;
try {
  const listResp = await $http.request({
    method: 'GET',
    url: `${baseUrl}/api/v1/workspaces/${slug}/projects/${projectId}/work-items/?search=${encodeURIComponent(itemName)}`,
    headers: { 'X-API-Key': apiKey }
  });
  const results = listResp.results || listResp;
  if (Array.isArray(results) && results.length > 0) {
    const match = results.find(r => r.name === itemName);
    if (match) existingId = match.id;
  }
} catch (e) {
  console.error('Plane search failed:', e.message);
}

const itemPayload = {
  name: itemName,
  description_html: `<p>Format: ${contentData.format || 'reel'}</p><p>Content ID: ${data.content_id || ''}</p>`,
  start_date: contentData.created_date || null,
  target_date: contentData.publish_date || null,
  module: moduleId || undefined
};

let planeResponse;
if (existingId) {
  // Update existing work item
  planeResponse = await $http.request({
    method: 'PATCH',
    url: `${baseUrl}/api/v1/workspaces/${slug}/projects/${projectId}/work-items/${existingId}/`,
    headers: { 'X-API-Key': apiKey, 'Content-Type': 'application/json' },
    body: itemPayload
  });
} else {
  // Create new work item
  planeResponse = await $http.request({
    method: 'POST',
    url: `${baseUrl}/api/v1/workspaces/${slug}/projects/${projectId}/work-items/`,
    headers: { 'X-API-Key': apiKey, 'Content-Type': 'application/json' },
    body: itemPayload
  });
}

return [{ json: { action, plane_response: planeResponse, work_item_id: planeResponse.id, operation: existingId ? 'updated' : 'created' } }];
